<template>
  <div class="agent-list-container">
    <div class="page-header">
      <h1>智能体列表</h1>
      <el-button type="primary" @click="$router.push('/agents/create')">
        <el-icon><plus /></el-icon> 创建新智能体
      </el-button>
    </div>

    <el-card v-loading="isLoading">
      <!-- 筛选工具栏 -->
      <div class="filter-toolbar">
        <el-input
          v-model="searchQuery"
          placeholder="搜索智能体名称或描述"
          clearable
          class="search-input"
        >
          <template #prefix>
            <el-icon><search /></el-icon>
          </template>
        </el-input>
        
        <el-select v-model="typeFilter" placeholder="类型筛选" clearable>
          <el-option label="所有类型" value="" />
          <el-option label="GPT-3.5" value="gpt-3.5" />
          <el-option label="GPT-4" value="gpt-4" />
          <el-option label="Claude 3" value="claude-3" />
          <el-option label="Gemini" value="gemini" />
          <el-option label="自定义" value="custom" />
          <el-option label="A2A兼容" value="a2a" />
        </el-select>
        
        <el-switch
          v-model="onlyShowMine"
          active-text="仅我的智能体"
          inactive-text="所有智能体"
        />
      </div>

      <el-alert
        v-if="error"
        :title="error"
        type="error"
        :closable="false"
        show-icon
      />

      <!-- 智能体列表 -->
      <div class="agent-list">
        <el-empty v-if="filteredAgents.length === 0" description="没有找到智能体" />
        
        <el-row :gutter="20">
          <el-col :xs="24" :sm="12" :md="8" :lg="6" v-for="agent in filteredAgents" :key="agent.id">
            <el-card class="agent-card" shadow="hover">
              <template #header>
                <div class="agent-header">
                  <span class="agent-name">{{ agent.name }}</span>
                  <el-tag size="small" :type="getAgentTypeTag(agent.agent_type)">
                    {{ getAgentTypeLabel(agent.agent_type) }}
                  </el-tag>
                </div>
              </template>
              
              <div class="agent-content">
                <p class="agent-description">{{ agent.description || '无描述' }}</p>
                
                <div class="agent-meta">
                  <div class="meta-item">
                    <el-icon><calendar /></el-icon>
                    <span>{{ formatDate(agent.created_at) }}</span>
                  </div>
                  
                  <div class="meta-item">
                    <el-icon><cpu /></el-icon>
                    <span>{{ agent.model_name }}</span>
                  </div>
                  
                  <div class="meta-item">
                    <el-icon><connection /></el-icon>
                    <span>{{ agent.is_a2a_compliant ? 'A2A兼容' : '非A2A兼容' }}</span>
                  </div>
                </div>
                
                <div class="agent-actions">
                  <el-button-group>
                    <el-button size="small" @click="$router.push(`/agents/${agent.id}`)">
                      <el-icon><view /></el-icon>
                      查看
                    </el-button>
                    
                    <el-button
                      size="small"
                      type="primary"
                      @click="$router.push(`/agents/${agent.id}/edit`)"
                      v-if="canEdit(agent)"
                    >
                      <el-icon><edit /></el-icon>
                      编辑
                    </el-button>
                    
                    <el-button
                      size="small"
                      type="success"
                      @click="$router.push(`/agents/${agent.id}/test`)"
                    >
                      <el-icon><operation /></el-icon>
                      测试
                    </el-button>
                    
                    <el-button
                      size="small"
                      type="danger"
                      @click="confirmDeleteAgent(agent)"
                      v-if="canDelete(agent)"
                    >
                      <el-icon><delete /></el-icon>
                    </el-button>
                  </el-button-group>
                </div>
              </div>
            </el-card>
          </el-col>
        </el-row>
      </div>
    </el-card>

    <!-- 删除确认对话框 -->
    <el-dialog
      v-model="deleteDialogVisible"
      title="确认删除"
      width="30%"
    >
      <span>确定要删除智能体 "{{ agentToDelete?.name }}" 吗？此操作不可撤销。</span>
      <template #footer>
        <span class="dialog-footer">
          <el-button @click="deleteDialogVisible = false">取消</el-button>
          <el-button type="danger" @click="deleteAgent">确认删除</el-button>
        </span>
      </template>
    </el-dialog>
  </div>
</template>

<script>
import { ref, computed, onMounted } from 'vue'
import { useRouter } from 'vue-router'
import { useAuthStore } from '@/store/auth'
import { useAgentStore } from '@/store/agent'
import { ElMessage, ElMessageBox } from 'element-plus'
import axios from 'axios'
import {
  Plus,
  Search,
  View,
  Edit,
  Delete,
  Calendar,
  Connection,
  Cpu,
  Operation
} from '@element-plus/icons-vue'

export default {
  name: 'AgentList',
  components: {
    Plus,
    Search,
    View,
    Edit,
    Delete,
    Calendar,
    Connection,
    Cpu,
    Operation
  },
  setup() {
    const router = useRouter()
    const authStore = useAuthStore()
    const agentStore = useAgentStore()
    
    // 状态变量
    const searchQuery = ref('')
    const typeFilter = ref('')
    const onlyShowMine = ref(false)
    const deleteDialogVisible = ref(false)
    const agentToDelete = ref(null)
    
    // 从store获取状态
    const isLoading = computed(() => agentStore.isLoading)
    const error = computed(() => agentStore.error)
    
    // 获取智能体列表
    const fetchAgents = async () => {
      await agentStore.fetchAgents()
      
      // 添加用户权限标记
      agentStore.agents.forEach(agent => {
        agent.can_edit = agent.owner === authStore.user?.id || authStore.user?.is_staff
        agent.can_delete = agent.owner === authStore.user?.id || authStore.user?.is_staff
      })
    }
    
    // 过滤智能体列表
    const filteredAgents = computed(() => {
      return agentStore.agents.filter(agent => {
        // 名称或描述匹配搜索关键词
        const matchesSearch = searchQuery.value === '' || 
          agent.name.toLowerCase().includes(searchQuery.value.toLowerCase()) ||
          (agent.description && agent.description.toLowerCase().includes(searchQuery.value.toLowerCase()))
        
        // 匹配类型筛选
        const matchesType = typeFilter.value === '' || agent.agent_type === typeFilter.value
        
        // 匹配所有者筛选
        const matchesOwner = !onlyShowMine.value || agent.owner === authStore.user?.id
        
        return matchesSearch && matchesType && matchesOwner
      })
    })
    
    // 确认删除对话框
    const confirmDeleteAgent = (agent) => {
      agentToDelete.value = agent
      deleteDialogVisible.value = true
    }
    
    // 删除智能体
    const deleteAgent = async () => {
      if (!agentToDelete.value) return
      
      try {
        await agentStore.deleteAgent(agentToDelete.value.id)
        
        // 关闭对话框
        deleteDialogVisible.value = false
        agentToDelete.value = null
      } catch (err) {
        console.error('删除智能体失败', err)
      }
    }
    
    // 格式化日期
    const formatDate = (dateString) => {
      if (!dateString) return '未知日期'
      const date = new Date(dateString)
      return date.toLocaleString('zh-CN', { 
        year: 'numeric', 
        month: '2-digit', 
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit'
      })
    }
    
    // 获取智能体类型的标签类型
    const getAgentTypeTag = (type) => {
      const typeMap = {
        'gpt-3.5': 'info',
        'gpt-4': 'success',
        'claude-3': 'warning',
        'gemini': 'danger',
        'custom': 'primary',
        'a2a': ''
      }
      return typeMap[type] || ''
    }
    
    // 获取智能体类型的显示标签
    const getAgentTypeLabel = (type) => {
      const labelMap = {
        'gpt-3.5': 'GPT-3.5',
        'gpt-4': 'GPT-4',
        'claude-3': 'Claude 3',
        'gemini': 'Gemini',
        'custom': '自定义',
        'a2a': 'A2A兼容'
      }
      return labelMap[type] || type
    }
    
    // 权限检查函数
    const canEdit = (agent) => {
      return agent.can_edit
    }
    
    const canDelete = (agent) => {
      return agent.can_delete
    }
    
    // 生命周期钩子
    onMounted(() => {
      fetchAgents()
    })
    
    return {
      isLoading,
      error,
      searchQuery,
      typeFilter,
      onlyShowMine,
      filteredAgents,
      deleteDialogVisible,
      agentToDelete,
      confirmDeleteAgent,
      deleteAgent,
      formatDate,
      getAgentTypeTag,
      getAgentTypeLabel,
      canEdit,
      canDelete
    }
  }
}
</script>

<style scoped>
.agent-list-container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 20px;
}

.page-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;
}

.filter-toolbar {
  display: flex;
  gap: 15px;
  margin-bottom: 20px;
  flex-wrap: wrap;
}

.search-input {
  min-width: 250px;
}

.agent-list {
  margin-top: 20px;
}

.agent-card {
  height: 100%;
  margin-bottom: 20px;
  display: flex;
  flex-direction: column;
}

.agent-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.agent-name {
  font-weight: bold;
  font-size: 16px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.agent-description {
  color: #606266;
  margin-bottom: 15px;
  overflow: hidden;
  text-overflow: ellipsis;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  line-clamp: 2;
  -webkit-box-orient: vertical;
  min-height: 40px;
}

.agent-meta {
  margin-bottom: 15px;
}

.meta-item {
  display: flex;
  align-items: center;
  margin-bottom: 5px;
  color: #909399;
}

.meta-item .el-icon {
  margin-right: 5px;
}

.agent-actions {
  margin-top: auto;
}

.dialog-footer {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
}
</style> 